// Make use of the access functions provided to initialise the variable arrays.
initialiseArrays(myStateVariables, myRates, myConstants, myComputedConstants, myAlgebraicVariables);
computeComputedConstants(time, myStateVariables, myRates, myConstants, myComputedConstants, myAlgebraicVariables);
computeRates(time, myStateVariables, myRates, myConstants, myComputedConstants, myAlgebraicVariables);
computeVariables(time, myStateVariables, myRates, myConstants, myComputedConstants, myAlgebraicVariables);

# Compute the parameters which require it, including the rates and variable values. model.initialise_arrays(my_state_variables, my_rates, my_constants, my_computed_constants, my_algebraic_variables) model.compute_computed_constants(voi, my_state_variables, my_rates, my_constants, my_computed_constants, my_algebraic_variables) model.compute_rates(voi, my_state_variables, my_rates, my_constants, my_computed_constants, my_algebraic_variables) model.compute_variables(voi, my_state_variables, my_rates, my_constants, my_computed_constants, my_algebraic_variables)
print(' STATE VARIABLES (units, initial value)') print('--------------------------------------------------------------------') for i in range(0, model.STATE_COUNT): print(' {} ({}, {})'.format(model.STATE_INFO[i]['name'], model.STATE_INFO[i]['units'], my_state_variables[i])) print() print(' CONSTANTS (units, initial value)') print('--------------------------------------------------------------------')
for v in range(0, model.CONSTANT_COUNT): print(' {} ({}, {})'.format(model.CONSTANT_INFO[v]['name'], model.CONSTANT_INFO[v]['units'], my_constants[v])) print() print(' COMPUTED CONSTANTS (units, initial value)') print('--------------------------------------------------------------------')
for v in range(0, model.COMPUTED_CONSTANT_COUNT): print(' {} ({}, {})'.format(model.COMPUTED_CONSTANT_INFO[v]['name'], model.COMPUTED_CONSTANT_INFO[v]['units'], my_computed_constants[v])) print() print(' ALGEBRAIC VARIABLES (units, initial value)') print('--------------------------------------------------------------------')
for v in range(0, model.ALGEBRAIC_VARIABLE_COUNT): print(' {} ({}, {})'.format(model.ALGEBRAIC_VARIABLE_INFO[v]['name'], model.ALGEBRAIC_VARIABLE_INFO[v]['units'], my_algebraic_variables[v])) print()
